const config=window.gqAdsTracking??null;if(!config?.endpoint||!config?.nonce){console.debug("GQ Ads: tracking config not found")}else{initTracking(config.endpoint,config.nonce)}function initTracking(endpoint,nonce){const getAdData=el=>{if(!(el instanceof HTMLElement))return null;const adId=parseInt(el.dataset.gqAdId??"0",10),placementId=parseInt(el.dataset.gqPlacementId??"0",10),groupId=parseInt(el.dataset.gqGroupId??"0",10),adType=el.dataset.gqAdType??"";if(adId<=0||placementId<=0)return null;return{adId,placementId,groupId,adType}},track=({adId,placementId,groupId,action})=>{const payload=JSON.stringify({ad_id:adId,placement_id:placementId,group_id:groupId,action,_wpnonce:nonce}),blob=new Blob([payload],{type:"application/json"});if(navigator.sendBeacon?.(endpoint,blob))return;fetch(endpoint,{method:"POST",keepalive:true,headers:{"Content-Type":"application/json"},body:payload}).catch(err=>{console.debug("GQ Ads: tracking error",err)})},impressionObserver=new IntersectionObserver(entries=>{for(const entry of entries){if(!entry.isIntersecting)continue;const data=getAdData(entry.target);if(data)track({...data,action:"impression"});impressionObserver.unobserve(entry.target)}},{threshold:0.5}),observeAds=()=>document.querySelectorAll(".gq-ad").forEach(el=>impressionObserver.observe(el));document.readyState==="loading"?document.addEventListener("DOMContentLoaded",observeAds):observeAds();const trackedClicks=new WeakSet;document.addEventListener("click",event=>{const adEl=event.target instanceof Element?event.target.closest(".gq-ad"):null;if(!adEl)return;const data=getAdData(adEl);if(!data)return;if(data.adType==="adsense")return;if(trackedClicks.has(adEl))return;trackedClicks.add(adEl);track({...data,action:"click"})})}
